namespace sv_b5d01886faa14e21bf89a04b2200b28c.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_b5d01886faa14e21bf89a04b2200b28c.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="d-flex">
        <!-- Left Sidebar -->
        <div class="pe-4" style="width: 25%; min-width: 220px;">
            <div class="card">
                <div class="card-header fw-bold">Filters</div>
                <div class="card-body">
                    <!-- Category checkboxes -->
                    <h6>Category</h6>
                    @if (_categories is null)
                    {
                        <p class="text-muted small">Loading categories…</p>
                    }
                    else
                    {
                        @foreach (var category in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                                       checked="@(_selectedCategories.Contains(category))"
                                       @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                            </div>
                        }
                    }

                    <hr />

                    <!-- Price range -->
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Min Price</label>
                        <input type="number" class="form-control form-control-sm" placeholder="Min"
                               @bind="_minPrice" min="0" step="0.01" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Max Price</label>
                        <input type="number" class="form-control form-control-sm" placeholder="Max"
                               @bind="_maxPrice" min="0" step="0.01" />
                    </div>

                    <hr />

                    <!-- In Stock Only -->
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    <!-- Action buttons -->
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync">Apply Filters</button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync">Clear Filters</button>
                    </div>
                </div>
            </div>
        </div>

        <!-- Main Content -->
        <div style="width: 75%;">
            <!-- Toolbar -->
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label me-2 mb-0">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto" @onchange="OnSortChangedAsync">
                        @foreach (var option in _sortOptions)
                        {
                            <option value="@option.Value" selected="@(option.Value == _sortBy)">@option.Label</option>
                        }
                    </select>
                </div>
                <div class="text-muted small">
                    @if (_result is not null && _result.TotalCount > 0)
                    {
                        var first = (_result.Page - 1) * _result.PageSize + 1;
                        var last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                        <span>Showing @first–@last of @_result.TotalCount products</span>
                    }
                </div>
            </div>

            <!-- Content states -->
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products…</p>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <h5 class="text-muted">No products found</h5>
                    <p class="text-muted">Try adjusting your filters.</p>
                </div>
            }
            else
            {
                <!-- Product Grid -->
                <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <div class="card h-100 product-card" @onclick="() => OnProductSelected.InvokeAsync(product.Id)" style="cursor: pointer;">
                                <div class="bg-light d-flex align-items-center justify-content-center" style="height: 180px;">
                                    <span class="text-muted" title="@product.Name">📷 @product.Name</span>
                                </div>
                                <div class="card-body d-flex flex-column">
                                    <h6 class="card-title">@product.Name</h6>
                                    <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                    <p class="card-text mb-1">@GetStarRating(product.Rating)</p>
                                    @if (!product.InStock)
                                    {
                                        <span class="badge bg-danger mb-2" style="width: fit-content;">Out of Stock</span>
                                    }
                                    <div class="mt-auto">
                                        <button class="btn btn-sm btn-success w-100"
                                                disabled="@(!product.InStock)"
                                                @onclick="() => { }" @onclick:stopPropagation="true">
                                            Add to Cart
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    }
                </div>

                <!-- Pagination -->
                @if (_totalPages > 1)
                {
                    <nav class="mt-4" aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)" disabled="@(_currentPage <= 1)">Previous</button>
                            </li>
                            @for (var i = 1; i <= _totalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">@pageNum</button>
                                </li>
                            }
                            <li class="page-item @(_currentPage >= _totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)" disabled="@(_currentPage >= _totalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    // Filter state
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    // Paging & sorting
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;
    private int _totalPages;

    private static readonly (string Label, string Value)[] _sortOptions =
    [
        ("Price: Low to High", "price_asc"),
        ("Price: High to Low", "price_desc"),
        ("Name: A-Z", "name_asc"),
        ("Rating: Highest", "rating_desc"),
    ];

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);

            var searchTask = ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
            _totalPages = (_result.TotalCount + PageSize - 1) / PageSize;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
        MinPrice: _minPrice,
        MaxPrice: _maxPrice,
        InStockOnly: _inStockOnly
    );

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task OnSortChangedAsync(ChangeEventArgs e)
    {
        _sortBy = e.Value?.ToString() ?? "price_asc";
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > _totalPages) return;
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task RetryAsync()
    {
        await LoadDataAsync();
    }

    private static string GetStarRating(double rating)
    {
        var rounded = (int)Math.Round(rating);
        return new string('★', rounded) + new string('☆', 5 - rounded);
    }
}

